-- ----------------------------------------------------------------------------
-- vw_project_metadata: Project overview
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_project_metadata WITH (security_invoker = ON) AS
SELECT
  t.project_id,
  t.name,                                                                       -- Effortlessly Invariant Rulesbooks (ERB)
  t.purpose,                                                                    -- Demonstrate that a single declarative rulebook can generate working code in multiple execution substrates that all produce identical results
  t.architecture,                                                               -- Rulebook-as-hub: effortless-rulebook.json is the durable SSoT; Airtable / LLM edits / admin portal are peer input spokes
  t.entry_point,                                                                -- ./start.sh boots the admin portal (web UI) — local dev experience for any rulebook project
  t.portal_url,                                                                 -- http://localhost:7777 — admin portal served by run-web-portal.sh
  t.proxy_url,                                                                  -- http://localhost:4242 — ssotme-proxy serving substrate transpilers as HTTP routes
  t.repository_root                                                             -- effortlessly-invariant-rulesbooks/
FROM project_metadata t;

-- ----------------------------------------------------------------------------
-- vw_execution_substrates: Runtime environments that execute business rules derived from the rulebook
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_execution_substrates WITH (security_invoker = ON) AS
SELECT
  t.substrate_id,
  t.name,                                                                       -- Human-readable substrate name
  t.technology,                                                                 -- Language/platform (PostgreSQL, Python, Go, Excel, OWL, PlantUML, etc.)
  t.relative_path,                                                              -- Path within repo: execution-substrates/{technology}/
  t.injector_script,                                                            -- Code generation script: inject-into-{technology}.py
  t.test_script,                                                                -- Conformance test script: take-test.py
  t.is_production,                                                              -- True if backed by an official Effortless tool; false if local implementation
  t.status,                                                                     -- Operational status (active, proof-of-concept, deprecated)
  t.description                                                                 -- Purpose and capabilities
FROM execution_substrates t;

-- ----------------------------------------------------------------------------
-- vw_orchestration_components: Central orchestration logic that coordinates rulebook loading, injection, and testing
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_orchestration_components WITH (security_invoker = ON) AS
SELECT
  t.component_id,
  t.name,
  t.file_path,                                                                  -- Relative path from repo root
  t.language,
  t.purpose,
  t.dependencies                                                                -- Comma-separated list of other components
FROM orchestration_components t;

-- ----------------------------------------------------------------------------
-- vw_rulebook_source_spokes: Peer input spokes that can write into effortless-rulebook.json. The rulebook JSON is the durable SSoT; these are interchangeable sources.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rulebook_source_spokes WITH (security_invoker = ON) AS
SELECT
  t.spoke_id,
  t.name,
  t.kind,                                                                       -- airtable | admin-portal | llm-direct | manual-json | reverse-sync
  t.direction,                                                                  -- input (writes into rulebook) | output (reads from rulebook) | bidirectional
  t.required,                                                                   -- False for all input spokes — any one is sufficient, none is required
  t.purpose,
  t.authority                                                                   -- On conflict, the rulebook JSON wins; spokes are the editors, not the SSoT
FROM rulebook_source_spokes t;

-- ----------------------------------------------------------------------------
-- vw_ssotme_proxy: Local HTTP transpiler server on localhost:4242. Each transpiler is an HTTP route; injectors are the route bodies. Used by `effortless build` to call substrate generators uniformly.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_ssotme_proxy WITH (security_invoker = ON) AS
SELECT
  t.route_id,
  t.route,                                                                      -- POST /{route-name}
  t.substrate_id,                                                               -- FK to ExecutionSubstrates.SubstrateId
  t.injector_script,                                                            -- Backing script that the route runs; null for upstream Effortless tools (e.g. airtable-to-rulebook)
  t.description
FROM ssotme_proxy t;

-- ----------------------------------------------------------------------------
-- vw_testing_framework: Conformance testing: prove all substrates compute identically
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_testing_framework WITH (security_invoker = ON) AS
SELECT
  t.test_id,
  t.name,
  t.file_path,
  t.purpose,
  t.scope                                                                       -- global (all substrates) or per-substrate
FROM testing_framework t;

-- ----------------------------------------------------------------------------
-- vw_rulebook_domains: Customer ontologies: each domain has its own rulebook + substrate generation
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rulebook_domains WITH (security_invoker = ON) AS
SELECT
  t.domain_id,
  t.domain_name,
  t.relative_path,                                                              -- rulebook-examples/{domain}/ — each domain is a self-contained Effortless project
  t.rulebook_path,                                                              -- Path to effortless-rulebook.json within domain
  t.complexity_level,                                                           -- minimal, moderate, advanced, or philosophical
  t.table_count,
  t.key_features,                                                               -- Comma-separated: string concat, relationships, aggregations, IF logic, meta-ontology, etc.
  t.purpose
FROM rulebook_domains t;

-- ----------------------------------------------------------------------------
-- vw_core_data_flows: End-to-end flows from rulebook to execution and testing
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_core_data_flows WITH (security_invoker = ON) AS
SELECT
  t.flow_id,
  t.name,
  t.steps,                                                                      -- Pipe-delimited sequence of steps
  t.triggers,                                                                   -- When this flow runs
  t.outputs,                                                                    -- Artifacts produced
  t.invariant                                                                   -- Hard rule the flow must preserve (e.g. write-through, SSoT precedence)
FROM core_data_flows t;

-- ----------------------------------------------------------------------------
-- vw_project_configuration: Configuration files and their purposes
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_project_configuration WITH (security_invoker = ON) AS
SELECT
  t.config_id,
  t.file_name,
  t.file_path,
  t.format,
  t.purpose,
  t.maintained_by                                                               -- human (manual edits) or tool (auto-generated)
FROM project_configuration t;

-- ----------------------------------------------------------------------------
-- vw_dependencies: External tools and their roles
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_dependencies WITH (security_invoker = ON) AS
SELECT
  t.dependency_id,
  t.name,
  t.version,
  t.type,                                                                       -- Language, tool, service, or external API
  t.purpose,
  t.required
FROM dependencies t;

-- ----------------------------------------------------------------------------
-- vw_app_users: Default users for local development and conformance testing. Lives in the rulebook so it travels with the project; production deployments should overlay these with a real identity provider.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_users WITH (security_invoker = ON) AS
SELECT
  t.user_id,
  t.email,                                                                      -- Login identifier (no password in dev mode; presence in this list = authorized)
  t.display_name,
  t.is_default,                                                                 -- True for the user the portal auto-selects on first boot
  t.notes
FROM app_users t;

-- ----------------------------------------------------------------------------
-- vw_user_roles: Admin portal access tiers. Drives both the navigation visible to the user and the RLS policies that Postgres applies to portal writes.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_user_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,
  t.name,
  t.access_level,                                                               -- read | full-admin
  t.can_edit_rulebook,
  t.can_run_builds,
  t.can_access_tech_tools,                                                      -- Tech Tools nest = raw Postgres explorer, ssotme-proxy logs, conformance internals
  t.can_switch_projects,
  t.can_manage_users,
  t.description
FROM user_roles t;

-- ----------------------------------------------------------------------------
-- vw_app_permissions: RLS-style policy table: declarative per-role allow/deny on portal API endpoints and on Postgres tables. Generated into Postgres on portal bootstrap as RLS policies.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_permissions WITH (security_invoker = ON) AS
SELECT
  t.permission_id,
  t.resource,                                                                   -- Logical resource: rulebook.entity, rulebook.field, rulebook.formula, build, test, users, tech-tools.postgres, tech-tools.proxy
  t."action",                                                                   -- read | create | update | delete | execute
  t.allow,
  t.rls_predicate                                                               -- Postgres RLS USING clause (when applicable); null for endpoint-only checks
FROM app_permissions t;

-- ----------------------------------------------------------------------------
-- vw_app_navigation: Primary navigation tree for the admin portal. Drives the left sidebar. Each node has a role gate and a target screen. This is the developer's narrative through a rulebook project.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_navigation WITH (security_invoker = ON) AS
SELECT
  t.nav_id,
  t.label,
  t.icon,                                                                       -- Lucide icon name
  t."order",
  t.story_beat                                                                  -- What this node teaches the developer in the rulebook narrative
FROM app_navigation t;

-- ----------------------------------------------------------------------------
-- vw_app_screens: Every screen in the admin portal. Each screen names the entities it reads/writes, the role it requires, and the story it tells.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_screens WITH (security_invoker = ON) AS
SELECT
  t.screen_id,
  t.path,                                                                       -- React Router path
  t.title,
  t.reads_entities,                                                             -- Comma-separated rulebook entities the screen reads
  t.writes_entities,                                                            -- Comma-separated rulebook entities the screen mutates (developer-only)
  t.layout,                                                                     -- split-detail | list | grid | dashboard | editor
  t.primary_action,
  t.story                                                                       -- What the developer learns / does on this screen
FROM app_screens t;

-- ----------------------------------------------------------------------------
-- vw_app_apis: Admin portal HTTP API surface. Express routes mounted by the portal backend.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_apis WITH (security_invoker = ON) AS
SELECT
  t.api_id,
  t.method,
  t.path,
  t.resource,                                                                   -- Logical resource for permission check (matches AppPermissions.Resource)
  t."action",
  t.writes_through,                                                             -- True if the endpoint must write to BOTH Postgres and the rulebook JSON
  t.description
FROM app_apis t;

-- ----------------------------------------------------------------------------
-- vw_add_tool_catalog: Tools the developer can install into the active project via the Add Tool screen. Same catalog the `effortless -install` CLI consumes; the portal is just a thin UI over the CLI so behaviour stays canonical.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_add_tool_catalog WITH (security_invoker = ON) AS
SELECT
  t.tool_id,
  t.name,
  t.category,                                                                   -- substrate | spoke-input | spoke-output | docs
  t.source,                                                                     -- local-proxy | effortless-registry
  t.install_url,                                                                -- URL passed to `effortless -install`
  t.output_path,                                                                -- Default RelativePath under the project (e.g. /python, /golang)
  t.description
FROM add_tool_catalog t;

-- ----------------------------------------------------------------------------
-- vw_build_pipeline: The effortless.json contract that both the admin portal and the CLI consume. There is ONE pipeline definition per project; both surfaces are thin wrappers around `effortless build` so they stay in lockstep.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_build_pipeline WITH (security_invoker = ON) AS
SELECT
  t.aspect_id,
  t.aspect,
  t.portal_location,                                                            -- Where in the portal this aspect surfaces
  t.cli_equivalent,
  t.authority                                                                   -- File or system that holds the canonical state
FROM build_pipeline t;

-- ----------------------------------------------------------------------------
-- vw_admin_portal_runtime: Runtime processes that ./start.sh boots and supervises.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_admin_portal_runtime WITH (security_invoker = ON) AS
SELECT
  t.process_id,
  t.name,
  t.command,
  t.port,
  t.depends_on,
  t.auto_restart,
  t.purpose
FROM admin_portal_runtime t;

